   284→    async function loadInterviews() {
   285→      try {
   286→        const data = await apiCall('/recruiter/interviews');
   287→        if (data.interviews) {
   288→          interviews = data.interviews;
   289→          updateStats(interviews);
   290→          renderInterviews();
