   631→
   632→    // Initialize
   633→    document.addEventListener('DOMContentLoaded', async () => {
   634→      const user = await checkAuth();
   635→      if (!user) {
   636→        window.location.href = '/login.html';
   637→        return;
   638→      }
   639→
   640→      // Get interview ID from URL or create new
   641→      const urlParams = new URLSearchParams(window.location.search);
   642→      const jobId = urlParams.get('job_id');
   643→
   644→      // Request camera access for preview
   645→      try {
   646→        mediaStream = await navigator.mediaDevices.getUserMedia({
   647→          video: { width: 1280, height: 720 },
   648→          audio: true
   649→        });
   650→        document.getElementById('preview-video').srcObject = mediaStream;
   651→        document.getElementById('preview-overlay').style.display = 'none';
   652→
   653→        // Initialize video analyzer
   654→        videoAnalyzer = new VideoAnalyzer();
   655→        const initialized = await videoAnalyzer.init();
   656→
   657→        if (initialized) {
   658→          console.log('Video analyzer ready');
   659→
   660→          // Listen for live score updates
   661→          videoAnalyzer.on('scores', (scores) => {
   662→            updateLiveMetrics(scores);
   663→          });
   664→        } else {
   665→          console.warn('Video analyzer initialization failed - continuing without analysis');
   666→        }
   667→      } catch (err) {
   668→        console.error('Camera access error:', err);
   669→        alert('Camera access is required for video interviews. Please allow permissions and reload.');
   670→      }
   671→    });
   672→
   673→    async function startInterview() {
   674→      try {
   675→        // Create interview session
   676→        const result = await apiCall('/interviews/start', {
   677→          method: 'POST',
   678→          body: JSON.stringify({
   679→            interview_type: 'video',
   680→            job_title: 'Software Developer', // TODO: Get from URL params or selection
   681→            job_description: 'General software development role'
   682→          })
   683→        });
   684→
   685→        if (!result.success) {
   686→          throw new Error('Failed to start interview');
   687→        }
   688→
   689→        interviewId = result.interview.id;
   690→        questions = result.questions;
   691→        responses = new Array(questions.length).fill(null);
   692→
   693→        // Update UI
   694→        updateProgress();
   695→        showState('recording');
   696→        displayQuestion(0);
   697→      } catch (err) {
   698→        console.error('Start interview error:', err);
   699→        alert('Failed to start interview. Please try again.');
   700→      }
   701→    }
   702→
   703→    function displayQuestion(index) {
   704→      currentQuestionIndex = index;
   705→      const question = questions[index];
   706→
   707→      document.getElementById('question-number').textContent = `Question ${index + 1} of ${questions.length}`;
   708→      document.getElementById('question-text').textContent = question.question;
   709→
   710→      // Reset timer
   711→      timeRemaining = 120;
   712→      updateTimer();
   713→
   714→      // Update progress
   715→      updateProgress();
   716→
   717→      // Setup video for recording
   718→      if (mediaStream) {
   719→        document.getElementById('recording-video').srcObject = mediaStream;
   720→      }
   721→    }
   722→
   723→    function startRecording() {
   724→      recordedChunks = [];
   725→
   726→      try {
   727→        mediaRecorder = new MediaRecorder(mediaStream, {
   728→          mimeType: 'video/webm;codecs=vp9'
   729→        });
   730→
   731→        mediaRecorder.ondataavailable = (event) => {
   732→          if (event.data.size > 0) {
   733→            recordedChunks.push(event.data);
   734→          }
   735→        };
   736→
   737→        mediaRecorder.onstop = handleRecordingStop;
   738→
   739→        mediaRecorder.start();
   740→
   741→        // Start video analysis
   742→        if (videoAnalyzer) {
   743→          videoAnalyzer.reset();
   744→          videoAnalyzer.startAnalysis(document.getElementById('recording-video'), 500);
   745→          document.getElementById('analysis-toggle').style.display = 'block';
   746→        }
   747→
   748→        // Update UI
   749→        document.getElementById('record-btn').style.display = 'none';
   750→        document.getElementById('stop-btn').style.display = 'inline-flex';
   751→        document.getElementById('recording-indicator').classList.add('active');
   752→
   753→        // Start timer
   754→        timerInterval = setInterval(() => {
   755→          timeRemaining--;
   756→          updateTimer();
   757→
   758→          if (timeRemaining <= 0) {
   759→            stopRecording();
   760→          }
   761→        }, 1000);
   762→      } catch (err) {
   763→        console.error('Recording error:', err);
   764→        alert('Failed to start recording. Please try again.');
   765→      }
   766→    }
   767→
   768→    function stopRecording() {
   769→      if (mediaRecorder && mediaRecorder.state !== 'inactive') {
   770→        mediaRecorder.stop();
   771→        clearInterval(timerInterval);
   772→
   773→        // Stop video analysis and save data
   774→        if (videoAnalyzer) {
   775→          videoAnalyzer.stopAnalysis();
   776→          const analysis = videoAnalyzer.getFinalAnalysis();
   777→
   778→          if (analysis) {
   779→            questionAnalysisData[currentQuestionIndex] = analysis;
   780→            console.log('Saved analysis for question', currentQuestionIndex, analysis.scores);
   781→          }
   782→
   783→          document.getElementById('analysis-toggle').style.display = 'none';
   784→          document.getElementById('analysis-overlay').classList.remove('active');
   785→        }
   786→
   787→        // Update UI
   788→        document.getElementById('record-btn').style.display = 'inline-flex';
   789→        document.getElementById('stop-btn').style.display = 'none';
   790→        document.getElementById('recording-indicator').classList.remove('active');
   791→      }
   792→    }
   793→
   794→    function handleRecordingStop() {
   795→      const blob = new Blob(recordedChunks, { type: 'video/webm' });
   796→      const videoUrl = URL.createObjectURL(blob);
   797→
   798→      // Show review state
   799→      document.getElementById('review-question-number').textContent =
   800→        `Question ${currentQuestionIndex + 1} of ${questions.length}`;
   801→      document.getElementById('review-question-text').textContent = questions[currentQuestionIndex].question;
   802→
   803→      const playbackVideo = document.getElementById('playback-video');
   804→      playbackVideo.src = videoUrl;
   805→
   806→      // Update retake button
   807→      const retakeBtn = document.getElementById('retake-btn');
   808→      const retakesForQuestion = retakesUsed[currentQuestionIndex] || 0;
   809→      if (retakesForQuestion >= 1) {
   810→        retakeBtn.disabled = true;
   811→        retakeBtn.textContent = '🔄 No retakes remaining';
   812→      } else {
   813→        retakeBtn.disabled = false;
   814→        retakeBtn.textContent = `🔄 Retake (${1 - retakesForQuestion} remaining)`;
   815→      }
   816→
   817→      showState('review');
   818→
   819→      // Store the blob temporarily
   820→      window.currentRecordingBlob = blob;
   821→    }
   822→
   823→    function retakeResponse() {
   824→      const retakesForQuestion = retakesUsed[currentQuestionIndex] || 0;
   825→      if (retakesForQuestion >= 1) {
   826→        alert('No retakes remaining for this question.');
   827→        return;
   828→      }
   829→
   830→      retakesUsed[currentQuestionIndex] = retakesForQuestion + 1;
   831→      showState('recording');
   832→      displayQuestion(currentQuestionIndex);
   833→    }
   834→
   835→    async function acceptResponse() {
   836→      // Show loading
   837→      document.getElementById('submit-btn').disabled = true;
   838→      document.getElementById('submit-btn').innerHTML = '<span class="loading-spinner"></span> Uploading...';
   839→
   840→      try {
   841→        // Upload video
   842→        const videoUrl = await uploadVideo(window.currentRecordingBlob, currentQuestionIndex);
   843→
   844→        // Save response
   845→        responses[currentQuestionIndex] = {
   846→          question_index: currentQuestionIndex,
   847→          video_url: videoUrl,
   848→          response_text: '[Video response]',
   849→          recorded_at: new Date().toISOString()
   850→        };
   851→
   852→        // Move to next question or complete
   853→        if (currentQuestionIndex < questions.length - 1) {
   854→          showState('recording');
   855→          displayQuestion(currentQuestionIndex + 1);
   856→        } else {
   857→          showCompleteState();
   858→        }
   859→      } catch (err) {
   860→        console.error('Upload error:', err);
   861→        alert('Failed to upload video. Please try again.');
   862→      } finally {
   863→        document.getElementById('submit-btn').disabled = false;
   864→        document.getElementById('submit-btn').innerHTML = 'Submit Interview';
   865→      }
   866→    }
   867→
   868→    async function uploadVideo(blob, questionIndex) {
   869→      const formData = new FormData();
   870→      formData.append('video', blob, `interview-${interviewId}-q${questionIndex}.webm`);
   871→      formData.append('interview_id', interviewId);
   872→      formData.append('question_index', questionIndex);
   873→
   874→      const response = await apiCall('/interviews/upload-video', {
   875→        method: 'POST',
   876→        body: formData,
   877→        isFormData: true
   878→      });
   879→
   880→      if (!response.success) {
   881→        throw new Error(response.error || 'Upload failed');
   882→      }
   883→
   884→      return response.video_url;
   885→    }
   886→
   887→    function showCompleteState() {
   888→      // Build responses list
   889→      const responsesList = document.getElementById('responses-list');
   890→      responsesList.innerHTML = responses.map((r, i) => `
   891→        <div class="response-item">
   892→          <div class="response-number">${i + 1}</div>
   893→          <div style="flex: 1;">
   894→            <div style="font-weight: 600; margin-bottom: 0.25rem;">${questions[i].question}</div>
   895→            <div class="response-status completed">✓ Video recorded</div>
   896→          </div>
   897→        </div>
   898→      `).join('');
   899→
   900→      showState('complete');
   901→    }
