   903→    async function submitInterview() {
   904→      document.getElementById('submit-btn').disabled = true;
   905→      document.getElementById('submit-btn').innerHTML = '<span class="loading-spinner"></span> Submitting...';
   906→
   907→      try {
   908→        // Submit all responses
   909→        for (let i = 0; i < responses.length; i++) {
   910→          if (responses[i]) {
   911→            await apiCall(`/interviews/${interviewId}/respond`, {
   912→              method: 'POST',
   913→              body: JSON.stringify(responses[i])
   914→            });
   915→          }
   916→        }
   917→
   918→        // Save video analysis data
   919→        await saveAnalysisData();
   920→
   921→        // Complete interview
   922→        await apiCall(`/interviews/${interviewId}/complete`, {
   923→          method: 'POST'
   924→        });
   925→
   926→        // Stop media stream
   927→        if (mediaStream) {
   928→          mediaStream.getTracks().forEach(track => track.stop());
   929→        }
   930→
   931→        // Redirect to results
   932→        alert('Interview submitted successfully!');
   933→        window.location.href = `/interview-analysis.html?interview_id=${interviewId}`;
   934→      } catch (err) {
   935→        console.error('Submit error:', err);
   936→        alert('Failed to submit interview. Please try again.');
   937→        document.getElementById('submit-btn').disabled = false;
   938→        document.getElementById('submit-btn').innerHTML = 'Submit Interview';
   939→      }
   940→    }
   941→
   942→    function showState(state) {
   943→      document.querySelectorAll('.setup-state, .recording-state, .review-state, .complete-state')
   944→        .forEach(el => el.classList.remove('active'));
   945→
   946→      if (state === 'recording') {
   947→        document.getElementById('recording-state').classList.add('active');
   948→      } else if (state === 'review') {
   949→        document.getElementById('review-state').classList.add('active');
   950→      } else if (state === 'complete') {
   951→        document.getElementById('complete-state').classList.add('active');
   952→      }
   953→    }
   954→
   955→    function updateProgress() {
   956→      const completed = responses.filter(r => r !== null).length;
   957→      const total = questions.length;
   958→      const percent = total > 0 ? (completed / total) * 100 : 0;
   959→
   960→      document.getElementById('progress-fill').style.width = `${percent}%`;
   961→      document.getElementById('progress-text').textContent = `Question ${completed} of ${total}`;
   962→    }
   963→
   964→    function updateTimer() {
   965→      const minutes = Math.floor(timeRemaining / 60);
   966→      const seconds = timeRemaining % 60;
   967→      const timerEl = document.getElementById('timer');
   968→
   969→      timerEl.textContent = `${minutes}:${seconds.toString().padStart(2, '0')}`;
   970→
   971→      if (timeRemaining <= 10) {
   972→        timerEl.classList.add('critical');
   973→      } else if (timeRemaining <= 30) {
   974→        timerEl.classList.add('warning');
   975→      } else {
   976→        timerEl.classList.remove('warning', 'critical');
   977→      }
   978→    }
