   997→
   998→      eyeContactEl.textContent = scores.eyeContact + '%';
   999→      eyeContactEl.className = 'metric-value ' + getMetricClass(scores.eyeContact);
  1000→
  1001→      postureEl.textContent = scores.headStability + '%';
  1002→      postureEl.className = 'metric-value ' + getMetricClass(scores.headStability);
  1003→
  1004→      presenceEl.textContent = scores.presence + '%';
  1005→      presenceEl.className = 'metric-value ' + getMetricClass(scores.presence);
  1006→    }
