  1008→    function getMetricClass(score) {
  1009→      if (score >= 70) return 'metric-good';
  1010→      if (score >= 50) return 'metric-warning';
  1011→      return 'metric-poor';
  1012→    }
  1013→
  1014→    // Save analysis data with interview submission
  1015→    async function saveAnalysisData() {
  1016→      if (!interviewId || Object.keys(questionAnalysisData).length === 0) {
  1017→        return;
  1018→      }
  1019→
  1020→      try {
  1021→        for (const [questionIndex, analysis] of Object.entries(questionAnalysisData)) {
  1022→          await apiCall('/interviews/save-analysis', {
  1023→            method: 'POST',
  1024→            body: JSON.stringify({
  1025→              interview_id: interviewId,
  1026→              question_index: parseInt(questionIndex),
  1027→              analysis_data: analysis,
  1028→              scores: analysis.scores
  1029→            })
  1030→          });
  1031→        }
  1032→        console.log('Video analysis saved successfully');
  1033→      } catch (err) {
