  } catch (err) {
    console.error('Error loading checklists:', err);
  }
}

// AI Automation simulation - auto-complete items
async function startAIAutomation(checklistId, items, completedItems) {
  const nextItem = items.find(item => !completedItems.includes(item.id));
  if (!nextItem) return;

  // Simulate AI processing time (3-8 seconds per item)
  const processingTime = 3000 + Math.random() * 5000;

  setTimeout(async () => {
    try {
      // Complete the item via API
      const res = await fetch(`/api/onboarding/checklists/${checklistId}/complete`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', ...getAuthHeaders() },
        body: JSON.stringify({ item_id: nextItem.id })
      });

      if (res.ok) {
        // Reload checklists to show progress
        loadChecklists();
      }
    } catch (err) {
      console.error('AI automation error:', err);
    }
  }, processingTime);
}

