  function scheduleInterview(appId) {
    window.location.href = `/recruiter-interviews.html?schedule=${appId}`;
  }

  // Make Offer functionality
  let currentOfferData = null;

  function makeOffer(appId, candidateId, candidateName, candidateEmail, jobId, jobTitle) {
    currentOfferData = { appId, candidateId, candidateName, candidateEmail, jobId, jobTitle };

    // Pre-fill the modal
    document.getElementById('offer-candidate-name').textContent = candidateName;
    document.getElementById('offer-job-title').value = jobTitle;

    // Set default start date to 2 weeks from now
    const startDate = new Date();
    startDate.setDate(startDate.getDate() + 14);
    document.getElementById('offer-start-date').value = startDate.toISOString().split('T')[0];

    // Show modal
    document.getElementById('offer-modal').style.display = 'flex';
  }

  function closeOfferModal() {
    document.getElementById('offer-modal').style.display = 'none';
    document.getElementById('offer-form').reset();
    currentOfferData = null;
  }

  async function submitOffer(e) {
    e.preventDefault();

    if (!currentOfferData) return;

    const offerData = {
      candidate_id: currentOfferData.candidateId,
      job_id: currentOfferData.jobId,
      title: document.getElementById('offer-job-title').value,
      salary: parseFloat(document.getElementById('offer-salary').value),
      start_date: document.getElementById('offer-start-date').value,
      benefits: document.getElementById('offer-benefits').value
    };

    try {
      // Create the offer
      const createResult = await apiCall('/onboarding/offers', {
        method: 'POST',
        body: JSON.stringify(offerData)
      });

      if (!createResult || createResult.error) {
        throw new Error(createResult?.error || 'Failed to create offer');
      }

      // Send the offer immediately
      const sendResult = await apiCall(`/onboarding/offers/${createResult.id}/send`, {
        method: 'POST'
      });

      // Update application status
      await apiCall(`/recruiter/applications/${currentOfferData.appId}/status`, {
        method: 'PUT',
        body: JSON.stringify({ status: 'offered' })
      });

      alert('Offer sent successfully to ' + currentOfferData.candidateName + '!');
      closeOfferModal();
      loadApplications();
    } catch (err) {
      console.error('Error creating offer:', err);
      alert('Failed to create offer: ' + err.message);
    }
  }
</script>

