  // If meeting link exists, open it
  if (interview.meeting_link) {
    window.open(interview.meeting_link, '_blank');
    return;
  }

  // Generate a Jitsi Meet room based on interview ID
  const roomName = `HireLoop-Interview-${id}-${Date.now().toString(36)}`;
  const meetingLink = `https://meet.jit.si/${roomName}`;

  // Update the interview with the meeting link
  updateMeetingLink(id, meetingLink).then(() => {
    window.open(meetingLink, '_blank');
  });
}

async function updateMeetingLink(interviewId, meetingLink) {
  try {
    await apiCall(`/recruiter/interviews/${interviewId}`, {
      method: 'PUT',
      body: JSON.stringify({ meeting_link: meetingLink })
    });
    // Refresh to show the link
    loadInterviews();
  } catch (err) {
    console.error('Failed to save meeting link:', err);
  }
}

