          candidate_id: existing.rows[0].candidate_id,
          job_id: existing.rows[0].job_id,
          new_status: status,
          recruiter_notes: recruiter_notes || null
        },
        req
      });
    }

    res.json({ success: true, application: result.rows[0] });
