function renderScheduledInterviews(interviews) {
  const container = document.getElementById('scheduled-interviews-list');

  container.innerHTML = interviews.map(interview => {
    const date = new Date(interview.scheduled_at);
    const now = new Date();
    const isUpcoming = date > now;
    const isSoon = date - now < 30 * 60 * 1000; // Within 30 minutes

    return `
      <div class="scheduled-interview-card ${isSoon ? 'soon' : ''}">
        <div class="interview-time-badge">
          <span class="interview-date">${date.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}</span>
          <span class="interview-time">${date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}</span>
        </div>
        <div class="interview-info">
          <h3>${interview.job_title || 'Interview'}</h3>
          <p>${interview.company_name || 'Company'}</p>
          <span class="interview-type-badge ${interview.interview_type || 'video'}">${interview.interview_type || 'Video Interview'}</span>
        </div>
        <div class="interview-action">
          ${isUpcoming ? `
            ${interview.meeting_link ?
              `<a href="${interview.meeting_link}" target="_blank" class="btn btn-primary ${isSoon ? 'pulse' : ''}">
                ${interview.interview_type === 'video' ? '🎥 Join Video Call' : '📞 Join'}
              </a>` :
              `<span class="interview-pending">Link will be available soon</span>`
            }
          ` : `<span class="interview-status">Completed</span>`}
        </div>
      </div>
    `;
  }).join('');
}

